select count(1)
from garden_contents

  and deleted = false

    and content_type = #{contentType}


    and audit_status = #{auditStatus}

select id, content_type, source_name, author_name, content_text, like_count, comment_count, audit_status, publish_time,
       created_at, updated_at, created_by, updated_by, deleted
from garden_contents

  and deleted = false

    and content_type = #{contentType}


    and audit_status = #{auditStatus}


order by id asc
limit #{pageSize} offset #{offset}

